import React from 'react';

const RubrosPanel = () => {
  const rubros = [
    "Comercio", "Tecnología", "Turismo", "Educación",
    "Salud", "Gastronomía", "Industria", "Artesanía",
    "Medios", "Construcción"
  ];

  return (
    <div className="min-h-screen bg-[#1e1e1e] flex items-center justify-center">
      {/* Fondo gris oscuro con borde inferior */}
      <div className="bg-[#2b2b2b] w-[90%] max-w-6xl rounded-xl overflow-hidden">
        {/* Encabezado gris y barra superior */}
        <div className="bg-[#3a3a3a] px-6 py-4 flex items-center justify-between">
          <h2 className="text-white text-xl font-semibold">DASHBOARDS</h2>
          <div className="flex items-center space-x-4">
            <input
              type="text"
              placeholder="Buscar..."
              className="rounded-full px-4 py-1 text-sm bg-white text-black"
            />
            <div className="text-white flex gap-3 text-xl">
              🏅 🔄 ⚙️ 🧠
            </div>
          </div>
        </div>

        {/* Sección rubros */}
        <div className="bg-[#121212] px-8 py-6">
          <h3 className="text-white text-lg mb-4">rubro</h3>

          <div className="bg-[#1c1c1c] p-6 rounded-lg">
            <h4 className="text-white text-center text-lg font-bold mb-6">nombre</h4>

            <div className="grid grid-cols-4 gap-4">
              {rubros.map((rubro, index) => (
                <div key={index} className="bg-white rounded-md px-4 py-2 text-center font-medium">
                  {rubro}
                </div>
              ))}
            </div>
          </div>
        </div>

        {/* Footer barra inferior */}
        <div className="bg-[#3a3a3a] text-white px-6 py-3 text-sm">
          EDITOR DE EMPRESAS
        </div>
      </div>
    </div>
  );
};

export default RubrosPanel;
